import matplotlib.pyplot as plt
import copy

def Clast_Show(Clasters_Function, Clasters_X = None, Clasters_Y = None):
    if Clasters_X is None:
        Clasters_X = {}
    if Clasters_Y is None:
        Clasters_Y = {}

    for i in range(1, len(Clasters_Function) + 1):
        print(Clasters_Function[i])
        Clasters_X[i] = []
        Clasters_Y[i] = []
        for j in range(len(Clasters_Function[i])):
            Clasters_X[i] += [Clasters_Function[i][j][0]]
            Clasters_Y[i] += [Clasters_Function[i][j][1]]
        plt.scatter(Clasters_X[i], Clasters_Y[i])
    plt.show()

def XY(Points_F, key):
    X_Coord_F = [0] * len(Points_F)
    Y_Coord_F = [0] * len(Points_F)
    for i in range(len(Points_F)):
        try:
            X_Coord_F[i] = float(Points_F[i].split(' ')[0])
            Y_Coord_F[i] = float(Points_F[i].split(' ')[1])
        except:
            print("Error while converting to float. i =", i)
    if key == "x":
        return X_Coord_F
    if key == "y":
        return Y_Coord_F
    else:
        return None

def BFS(x, y, R, X_Coord, Y_Coord, Clasters = None, n=None, Visited = None):
    if n is None:
        n = 1
    if Clasters is None:
        Clasters = {1: []}
    elif Visited is None:
        Clasters[n] = []
    if Visited is None:
        Visited = []

    X_Coords = copy.deepcopy(X_Coord)
    Y_Coords = copy.deepcopy(Y_Coord)
    i = 0
    while i < len(X_Coords):
        F = True
        X = X_Coords[i]
        Y = Y_Coords[i]
        if x-R < X < x+R and not(X in Visited):
            if y-R < Y < y+R and not(Y in Visited):
                Clasters[n] += [[X, Y]]
                X_Coords.pop(i)
                Y_Coords.pop(i)
                F = False
        if F:
            i += 1

    Visited.append([x, y])

    if len(X_Coords) == 0:
        return Clasters

    for j in range(len(Visited),len(Clasters[n])):
        if not(Clasters[n][j] in Visited):
            return BFS(Clasters[n][j][0], Clasters[n][j][1], R, X_Coords, Y_Coords, Clasters, n, Visited)
    c = 0
    for o in range(len(Clasters[n])):
        if (Clasters[n][o] in Visited):
            c += 1
    if c == len(Clasters[n]):
        return BFS(X_Coords[0], Y_Coords[0], R, X_Coords, Y_Coords, Clasters, n+1, Visited=None)

